    if (value === undefined || value === null) return;
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    const s = String(value).trim();
    if (s) out.push(s);
  };
  for (const value of values) visit(value);
  return Array.from(new Set(out));
